  """

  use GenServer

  @table_name :session_store
  @cleanup_interval 300_000  # 5 minutes
  @max_age 86_400  # 24 hours

  # --- Client API ---

  def start_link(opts \\ []) do
    GenServer.start_link(__MODULE__, opts, name: __MODULE__)
  end

  def put(session_id, session_data) do
    now = System.system_time(:second)
    binary = :erlang.term_to_binary(session_data, [:compressed])
    :ets.insert(@table_name, {session_id, binary, now})
    :ok
  end

  def get(session_id) do
    case :ets.lookup(@table_name, session_id) do
      [{^session_id, binary, timestamp}] ->
        now = System.system_time(:second)

        if now - timestamp <= @max_age do
          session_data = :erlang.binary_to_term(binary, [:safe])
          {:ok, session_data}
        else
          delete(session_id)
          {:error, :session_expired}
        end

      [] ->
        {:error, :not_found}
    end
  end

  def delete(session_id) do
    :ets.delete(@table_name, session_id)
    :ok
  end

  def exists?(session_id) do
    :ets.member(@table_name, session_id)
  end

  # --- Server Callbacks ---

  @impl true
  def init(_opts) do
    table = :ets.new(@table_name, [:named_table, :public, :set, read_concurrency: true])
    schedule_cleanup()
    {:ok, %{table: table}}
  end

  @impl true
  def handle_info(:cleanup, state) do
    cleanup_expired_sessions()
    schedule_cleanup()
    {:noreply, state}
  end

  defp schedule_cleanup do
    Process.send_after(self(), :cleanup, @cleanup_interval)
  end

  defp cleanup_expired_sessions do
    now = System.system_time(:second)
    cutoff = now - @max_age

    :ets.select_delete(@table_name, [
      {{:_, :_, :"$1"}, [{:<, :"$1", cutoff}], [true]}
    ])
  end
end